query:
SELECT COUNT(*)
FROM "hdb_resale_prices"
WHERE CAST(block AS TEXT) !~ '^[A-Za-z0-9]{1,10}$';

SELECT COUNT(*)
FROM "hdb_resale_prices"
WHERE CAST(month AS TEXT) !~ '^[0-9]{4}-(0[1-9]|1[0-2])$';

SELECT COUNT(*)
FROM "hdb_resale_prices"
WHERE CAST(lease_commence_date AS TEXT) !~ '^[0-9]{4}$';
